public class UsersControllerTests
{
    private readonly Mock<IUserService> _mockService;
    private readonly UsersController _controller;

    public UsersControllerTests()
    {
        _mockService = new Mock<IUserService>();
        _controller = new UsersController(
            _mockService.Object,
            Mock.Of<ILogger<UsersController>>()
        );
    }
}

[Fact]
public async Task GetUser_WhenUserExists_ReturnsOkWithUser()
{
    // Arrange
    var userDto = new UserDto { Id = 1, Name = "John", Email = "john@example.com" };
    _mockService.Setup(s => s.GetByIdAsync(1)).ReturnsAsync(userDto);

    // Act
    var result = await _controller.GetUser(1);

    // Assert
    var okResult = Assert.IsType<OkObjectResult>(result.Result);
    var returned = Assert.IsType<UserDto>(okResult.Value);
    Assert.Equal(1, returned.Id);
}

[Fact]
public async Task GetUser_WhenUserNotFound_ReturnsNotFound()
{
    _mockService.Setup(s => s.GetByIdAsync(999)).ReturnsAsync((UserDto?)null);
    var result = await _controller.GetUser(999);
    Assert.IsType<NotFoundResult>(result.Result);
}

[Theory]
[InlineData("", "Email is required")]
[InlineData("not-an-email", "Email format is invalid")]
[InlineData("a@b", "Email domain too short")]
public async Task CreateUser_WithInvalidEmail_ReturnsBadRequest(
    string email, string expectedError)
{
    var dto = new CreateUserDto { Name = "Test", Email = email };
    var result = await _controller.CreateUser(dto);
    var badRequest = Assert.IsType<BadRequestObjectResult>(result.Result);
    Assert.Contains(expectedError, badRequest.Value?.ToString());
}
